proof fn phi_2_filter_empty_identity(pred: spec_fn(int) -> bool)
    ensures
        Seq::<int>::empty().filter(pred) == Seq::<int>::empty(),
{
    lemma_if_everything_in_seq_satisfies_filter_then_filter_is_identity(Seq::<int>::empty(), pred);
}

proof fn phi_3_filter_singleton_satisfying(x: int, pred: spec_fn(int) -> bool)
    requires
        pred(x),
    ensures
        seq![x].filter(pred) == seq![x],
{
    lemma_if_everything_in_seq_satisfies_filter_then_filter_is_identity(seq![x], pred);
}

proof fn phi_4_filter_idempotent(s: Seq<int>, pred: spec_fn(int) -> bool)
    ensures
        s.filter(pred).filter(pred) == s.filter(pred),
{
    let filtered = s.filter(pred);
    assert(forall |i: int| 0 <= i < filtered.len() ==> pred(filtered[i])) by {
        reveal(Seq::filter);
        // filter output only contains elements satisfying pred
        admit(); // may need vstd filter lemma
    }
    lemma_if_everything_in_seq_satisfies_filter_then_filter_is_identity(filtered, pred);
}

proof fn phi_5_filter_preserves_all_satisfying_length(s: Seq<int>, pred: spec_fn(int) -> bool)
    requires
        forall |i: int| 0 <= i < s.len() ==> pred(s[i]),
    ensures
        s.filter(pred).len() == s.len(),
{
    lemma_if_everything_in_seq_satisfies_filter_then_filter_is_identity(s, pred);
}
